package Java;

public class OddNumber {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		
	    int num= 12;
	    
	    if (num%2==0) {
	    	System.out.print("The given " + num+ " is odd number");
	    }else {
	    	System.out.print("The given " + num+ " is not odd number");
	    }
	}

}
